import "./footer.css";

function Footer() {
  const year = new Date().getFullYear();

  return (
    <footer className="site-footer">
      <div className="site-footer-inner">
        <p className="site-footer-copy">© {year} MyPortfolio. All rights reserved.</p>
        <a href="prathmeshn789@gmail.com" className="site-footer-link">
          Contact
        </a>
      </div>
    </footer>
  );
}

export default Footer;
